import React from 'react'
import {
    SideDrawerWrapper,
    ItemWrapper,
    LabelWrapper,
    IconWrapper,
    HomeIcon,
    FaceIcon,
} from './style'

const pages = [
    { title: 'Home', icon: HomeIcon, path: '/' },
    { title: 'About me', icon: FaceIcon, path: '/about'},
]

const SideDrawer = ({
    isOpenSideDrawer,
    toggleSideDrawer,
}) => {

    return (
        <SideDrawerWrapper isOpen={isOpenSideDrawer}>
            {pages.map((page) => {
                return (
                <ItemWrapper
                    key={page.title}
                    to={page.path}
                    onClick={toggleSideDrawer}
                >
                    <IconWrapper>
                        <page.icon />
                    </IconWrapper>
                    <LabelWrapper>{page.title}</LabelWrapper>
                </ItemWrapper>
            )})}
        </SideDrawerWrapper>
    )
}

export default SideDrawer
