import React, { useState, useCallback } from 'react';
import Header from '../Header';
import SideDrawer from '../SideDrawer';
import Backdrop from '../Backdrop';
import Routes from '../../routes'
import { MainWrapper } from './style'

const Main = () => {
  const [isOpenSideDrawer, setIsOpenSideDrawer] = useState(false)

  const toggleSideDrawer = useCallback(() => (
    setIsOpenSideDrawer((prev) => !prev)
  ), [])

  return (
    <MainWrapper>
      <Header toggleSideDrawer={toggleSideDrawer}/>
      <SideDrawer isOpenSideDrawer={isOpenSideDrawer} toggleSideDrawer={toggleSideDrawer} />
      {isOpenSideDrawer && (
          <Backdrop toggleSideDrawer={toggleSideDrawer}/>
      )}

      <Routes />
    </MainWrapper>
  );
}

export default Main;
